const now = new Date();
return [{
  json: {
    subject: `[MeetCore] No recordings found — ${now.toLocaleDateString('en-US', {weekday:'long', month:'long', day:'numeric'})}`,
    checked_at: now.toLocaleTimeString('en-US', {hour:'2-digit', minute:'2-digit'}),
    checked_date: now.toLocaleDateString('en-US', {weekday:'long', month:'long', day:'numeric', year:'numeric'}),
    platforms: 'Zoom · Google Meet · Microsoft Teams'
  }
}];

